import { useState, useMemo } from 'react';
import { Mic, Square, Volume2 } from 'lucide-react';

export default function VoiceChat() {
  const [isRecording, setIsRecording] = useState(false);
  const heights = useMemo(() => [...Array(15)].map(() => Math.max(10, Math.random() * 64)), []);
  const [transcript, setTranscript] = useState('');

  const toggleRecording = () => {
    setIsRecording(!isRecording);
    if (!isRecording) {
      setTranscript('Listening... Speak your mind.');
    } else {
      setTranscript('I hear you. You mentioned feeling overwhelmed yesterday. Let\'s talk about what triggered it today.');
    }
  };

  return (
    <div className="animate-fade-in flex flex-col items-center justify-center min-h-[70vh] gap-12 px-4 relative">

      {/* Background blobs for ethereal UI */}
      <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-skyBlue/20 rounded-full blur-[100px] -z-10 mix-blend-multiply"></div>
      <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-lavender/20 rounded-full blur-[100px] -z-10 mix-blend-multiply"></div>

      <div className="text-center max-w-xl">
        <h1 className="text-4xl font-heading font-extrabold text-[#2c2f30] mb-4">Voice Sanctuary</h1>
        <p className="text-gray-500 font-body text-lg">Speak freely. We're here to listen.</p>
      </div>

      <div className="glass w-full max-w-2xl rounded-[3rem] p-10 flex flex-col items-center gap-10 shadow-2xl relative overflow-hidden min-h-[300px] border border-white/50">

        {/* Transcript Area */}
        <div className="flex-1 flex items-center justify-center text-center px-8 w-full">
          <p className="text-2xl font-heading font-medium text-gray-700 leading-relaxed transition-all duration-500">
            {transcript || 'Tap the microphone to start a session.'}
          </p>
        </div>

        {/* Visualizer Mock */}
        {isRecording && (
          <div className="flex items-center gap-1.5 h-16 w-full justify-center opacity-70">
            {[...Array(15)].map((_, i) => (
              <div 
                key={i} 
                className="w-1.5 bg-gradient-to-t from-primary to-mint rounded-full animate-pulse"
                style={{ 
                  height: `${heights[i]}px`,
                  animationDelay: `${i * 0.1}s`,
                  animationDuration: '0.5s'
                }}
              ></div>
            ))}
          </div>
        )}

        {/* Controls */}
        <div className="flex items-center gap-6 mt-auto">
          <button className="w-12 h-12 rounded-full glass-dark flex items-center justify-center text-white hover:bg-gray-800 transition">
            <Volume2 size={20} />
          </button>

          <button 
            onClick={toggleRecording}
            className={`w-20 h-20 rounded-full flex items-center justify-center shadow-xl transition-all duration-300 hover:scale-105 ${
              isRecording 
                ? 'bg-rose-500 text-white shadow-rose-500/40 animate-pulse' 
                : 'bg-gradient-to-tr from-primary to-lavender text-white shadow-primary/40'
            }`}
          >
            {isRecording ? <Square size={28} /> : <Mic size={32} />}
          </button>

          <button className="w-12 h-12 rounded-full glass flex items-center justify-center text-gray-500 hover:text-gray-800 hover:bg-white transition">
            <span className="font-bold text-xs">EN</span>
          </button>
        </div>
      </div>
    </div>
  );
}
